??\r\n    bucketName: jeecgdev\r\n    staticDomain: ??  \r\n  file-view-domain: 127.0.0.1:8012\r\n  minio:\r\n    minio_url: http://minio.jeecg.com\r\n    minio_name: ??\r\n    minio_pass: ??\r\n    bucketName: otatest\r\n  jmreport:\r\n    saasMode:\r\n    firewall:\r\n      dataSourceSafe: false\r\n      lowCodeMode: dev\r\n  wps:\r\n    domain: https://wwo.wps.cn/office/\r\n    appid: ??\r\n    appsecret: ??\r\n  xxljob:\r\n    enabled: false\r\n    adminAddresses: http://jeecg-boot-xxljob:9080/xxl-job-admin\r\n    appname: ${spring.application.name}\r\n    accessToken: \'\'\r\n    logPath: logs/jeecg/job/jobhandler/\r\n    logRetentionDays: 30\r\n  redisson:\r\n    address: jeecg-boot-redis:6379\r\n    password:\r\n    type: STANDALONE\r\n    enabled: true\r\n  ai-chat:\r\n    enabled: false\r\n    apiKey: \"？？？？\"\r\n    apiHost: \"https://api.openai.com\"\r\n    timeout: 60\r\n  ai-rag:\r\n    embed-store:\r\n      host: 127.0.0.1\r\n      port: 5432\r\n      database: postgres\r\n      user: postgres\r\n      password: postgres\r\n      table: embeddings\r\ncas:\r\n  prefixUrl: http://localhost:8888/cas\r\nknife4j:\r\n  production: false\r\n  basic:\r\n    enable: false\r\n    username: jeecg\r\n    password: jeecg1314\r\njustauth:\r\n  enabled: true\r\n  type:\r\n    GITHUB:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/github/callback\r\n    WECHAT_ENTERPRISE:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/wechat_enterprise/callback\r\n      agent-id: ??\r\n    DINGTALK:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/dingtalk/callback\r\n  cache:\r\n    type: default\r\n    prefix: \'demo::\'\r\n    timeout: 1h\r\nthird-app:\r\n  enabled: false\r\n  type:\r\n    WECHAT_ENTERPRISE:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??\r\n    DINGTALK:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??', '1c1b20938e6641f1c9a5c0ea94a0c1bd', '2026-07-06 22:48:40', '2026-07-06 22:48:40', 'nacos', '0:0:0:0:0:0:0:1', '', 'public', NULL, NULL, NULL, 'yaml', NULL, '');
