INSERT INTO `his_config_info` VALUES (0, 1, 'jeecg.yaml', 'DEFAULT_GROUP', '', 'server:\r\n  tomcat:\r\n    max-swallow-size: -1\r\n  error:\r\n    include-exception: true\r\n    include-stacktrace: ALWAYS\r\n    include-message: ALWAYS\r\n  compression:\r\n    enabled: true\r\n    min-response-size: 1024\r\n    mime-types: application/javascript,application/json,application/xml,text/html,text/xml,text/plain,text/css,image/*\r\nmanagement:\r\n  health:\r\n    mail:\r\n      enabled: false\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: metrics,httpexchanges,jeecghttptrace\r\n    health:\r\n      sensitive: true\r\n  endpoint:\r\n    health:\r\n      show-details: ALWAYS\r\nspring:\r\n  servlet:\r\n    multipart:\r\n      max-file-size: 10MB\r\n      max-request-size: 10MB\r\n  mail:\r\n    host: smtp.163.com\r\n    username: jeecgos@163.com\r\n    password: ??\r\n    properties:\r\n      mail.smtp.timeout: 10000\r\n      mail.smtp.connectiontimeout: 10000\r\n      mail.smtp.writetimeout: 10000\r\n      mail.smtp.auth: true\r\n      smtp.ssl.enable: true\r\n  quartz:\r\n    job-store-type: jdbc\r\n    jdbc:\r\n      initialize-schema: embedded\r\n    auto-startup: false\r\n    startup-delay: 1s\r\n    overwrite-existing-jobs: true\r\n    properties:\r\n      org:\r\n        quartz:\r\n          scheduler:\r\n            instanceName: MyScheduler\r\n            instanceId: AUTO\r\n          jobStore:\r\n            class: org.springframework.scheduling.quartz.LocalDataSourceJobStore\r\n            driverDelegateClass: org.quartz.impl.jdbcjobstore.StdJDBCDelegate\r\n            tablePrefix: QRTZ_\r\n            isClustered: true\r\n            misfireThreshold: 12000\r\n            clusterCheckinInterval: 15000\r\n          threadPool:\r\n            class: org.quartz.simpl.SimpleThreadPool\r\n            threadCount: 10\r\n            threadPriority: 5\r\n            threadsInheritContextClassLoaderOfInitializingThread: true\r\n  jackson:\r\n    date-format: yyyy-MM-dd HH:mm:ss\r\n    time-zone: GMT+8\r\n  aop:\r\n    proxy-target-class: true\r\n  jpa:\r\n    open-in-view: false\r\n  freemarker:\r\n    suffix: .ftl\r\n    content-type: text/html\r\n    charset: UTF-8\r\n    cache: false\r\n    prefer-file-system-access: false\r\n    template-loader-path:\r\n      - classpath:/templates\r\n  mvc:\r\n    static-path-pattern: /**\r\n    pathmatch:\r\n      matching-strategy: ant_path_matcher\r\n  resource:\r\n    static-locations: classpath:/static/,classpath:/public/\r\n  autoconfigure:\r\n    exclude:\r\n      - com.alibaba.druid.spring.boot3.autoconfigure.DruidDataSourceAutoConfigure\r\n      - org.springframework.boot.autoconfigure.flyway.FlywayAutoConfiguration\r\nmybatis-plus:\r\n  mapper-locations: classpath*:org/jeecg/**/xml/*Mapper.xml\r\n  global-config:\r\n    banner: false\r\n    db-config:\r\n      id-type: ASSIGN_ID\r\n      table-underline: true\r\n  configuration:\r\n    call-setters-on-nulls: true\r\nlogging:\r\n  level:\r\n    org.springframework.context.support.PostProcessorRegistrationDelegate: error\r\n    org.flywaydb: debug\r\n    org.jeecg.modules.system.mapper: info\r\n    org.jeecg.modules.demo.test.mapper: info\r\nliteflow:\r\n  print-banner: false\r\n  parse-mode: PARSE_ONE_ON_FIRST_EXEC\r\n  rule-source-ext-data-map:\r\n    applicationName: jeecg\r\n    #是否开启SQL日志\r\n    sqlLogEnabled: true\r\n    chainTableName: airag_flow\r\n    #编排规则表中应用名称存储字段名\r\n    chainApplicationNameField: application_name\r\n    #规则名称存储的字段名\r\n    chainNameField: id\r\n    #EL表达式的字段(只存EL)\r\n    elDataField: chain\r\n    chainCustomSql: select id, application_name, chain from airag_flow where status = \'enable\' and chain is not null', '7da782052bc66c0ee604183e75ef477c', '2026-07-06 22:47:58', '2026-07-06 22:47:59', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 2, 'jeecg-dev.yaml', 'DEFAULT_GROUP', '', 'spring:\r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n        allow:\r\n      web-stat-filter:\r\n        enabled: true\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        wall:\r\n          selectWhereAlwayTrueCheck: false\r\n        stat:\r\n          merge-sql: true\r\n          slow-sql-millis: 5000\r\n      datasource:\r\n        master:\r\n          url: jdbc:mysql://jeecg-boot-mysql:3306/jeecg-boot?characterEncoding=UTF-8&useUnicode=true&useSSL=false&tinyInt1isBit=false&allowPublicKeyRetrieval=true&serverTimezone=Asia/Shanghai\r\n          username: root\r\n          password: root\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n        # sharding-db:\r\n        #  driver-class-name: org.apache.shardingsphere.driver.ShardingSphereDriver\r\n        #  url: jdbc:shardingsphere:nacos:sharding.yaml?serverAddr=${spring.cloud.nacos.config.server-addr}&namespace=${spring.cloud.nacos.config.namespace}&group=${spring.cloud.nacos.config.group}\r\n  data:\r\n    redis:\r\n      database: 0\r\n      host: jeecg-boot-redis\r\n      password:\r\n      port: 6379\r\n  rabbitmq:\r\n    host: jeecg-boot-rabbitmq\r\n    username: guest\r\n    password: guest\r\n    port: 5672\r\n    publisher-confirms: true\r\n    publisher-returns: true\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual\r\n        concurrency: 1\r\n        max-concurrency: 1\r\n        retry:\r\n          enabled: true\r\n  flyway:\r\n    enabled: false\r\n    locations: classpath:flyway/sql/mysql\r\n    clean-disabled: true\r\nminidao:\r\n  base-package: org.jeecg.modules.jmreport.*,org.jeecg.modules.drag.*\r\njeecg:\r\n  firewall:\r\n    dataSourceSafe: false\r\n    lowCodeMode: dev\r\n  signatureSecret: dd05f1c54d63749eda95f9fa6d49v442a\r\n  signUrls: /sys/dict/getDictItems/*,/sys/dict/loadDict/*,/sys/dict/loadDictOrderByValue/*,/sys/dict/loadDictItem/*,/sys/dict/loadTreeData,/sys/api/queryTableDictItemsByCode,/sys/api/queryFilterTableDictInfo,/sys/api/queryTableDictByKeys,/sys/api/translateDictFromTable,/sys/api/translateDictFromTableByKeys\r\n  uploadType: local\r\n  domainUrl:\r\n    pc: http://localhost:3100\r\n    app: http://localhost:8051\r\n  path:\r\n    upload: /opt/upFiles\r\n    webapp: /opt/webapp\r\n  shiro:\r\n    excludeUrls: /test/jeecgDemo/demo3,/test/jeecgDemo/redisDemo/**,/category/**,/visual/**,/map/**,/jmreport/bigscreen2/**\r\n  oss:\r\n    endpoint: oss-cn-beijing.aliyuncs.com\r\n    accessKey: ??\r\n    secretKey: ??\r\n    bucketName: jeecgdev\r\n    staticDomain: ??  \r\n  file-view-domain: 127.0.0.1:8012\r\n  minio:\r\n    minio_url: http://minio.jeecg.com\r\n    minio_name: ??\r\n    minio_pass: ??\r\n    bucketName: otatest\r\n  jmreport:\r\n    saasMode:\r\n    firewall:\r\n      dataSourceSafe: false\r\n      lowCodeMode: dev\r\n  wps:\r\n    domain: https://wwo.wps.cn/office/\r\n    appid: ??\r\n    appsecret: ??\r\n  xxljob:\r\n    enabled: true\r\n    adminAddresses: http://jeecg-boot-xxljob:9080\r\n    appname: ${spring.application.name}\r\n    accessToken: \'\'\r\n    logPath: logs/jeecg/job/jobhandler/\r\n    logRetentionDays: 30\r\n  redisson:\r\n    address: jeecg-boot-redis:6379\r\n    password:\r\n    type: STANDALONE\r\n    enabled: true\r\n  ai-chat:\r\n    enabled: false\r\n    apiKey: \"？？？？\"\r\n    apiHost: \"https://api.openai.com\"\r\n    timeout: 60\r\n  ai-rag:\r\n    embed-store:\r\n      host: 127.0.0.1\r\n      port: 5432\r\n      database: postgres\r\n      user: postgres\r\n      password: postgres\r\n      table: embeddings\r\ncas:\r\n  prefixUrl: http://localhost:8888/cas\r\nknife4j:\r\n  production: false\r\n  basic:\r\n    enable: false\r\n    username: jeecg\r\n    password: jeecg1314\r\njustauth:\r\n  enabled: true\r\n  type:\r\n    GITHUB:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/github/callback\r\n    WECHAT_ENTERPRISE:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/wechat_enterprise/callback\r\n      agent-id: ??\r\n    DINGTALK:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/dingtalk/callback\r\n  cache:\r\n    type: default\r\n    prefix: \'demo::\'\r\n    timeout: 1h\r\nthird-app:\r\n  enabled: false\r\n  type:\r\n    WECHAT_ENTERPRISE:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??\r\n    DINGTALK:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??', '3c0bb9da0a7bf310132e6826ea00b3ef', '2026-07-06 22:48:18', '2026-07-06 22:48:19', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 3, 'jeecg-dev-satoken.yaml', 'DEFAULT_GROUP', '', '################ Sa-Token 配置 (文档: https://sa-token.cc) ################\r\nsa-token:\r\n  # token 名称（同时也是 cookie 名称）\r\n  token-name: X-Access-Token\r\n  # token 有效期（单位：秒） 默认30天，-1 代表永久有效\r\n  timeout: 2592000\r\n  # token 最低活跃频率（单位：秒），如果 token 超过此时间没有访问系统就会被冻结，默认-1 代表不限制，永不冻结\r\n  active-timeout: -1\r\n  # 是否允许同一账号多地同时登录 （为 true 时允许一起登录, 为 false 时新登录挤掉旧登录）\r\n  is-concurrent: false\r\n  # 在多人登录同一账号时，是否共用一个 token （为 true 时所有登录共用一个 token, 为 false 时每次登录新建一个 token）\r\n  is-share: false\r\n  # token 风格（使用jwt-simple保持与原JWT token格式一致）\r\n  token-style: jwt-simple\r\n  # 是否输出操作日志\r\n  is-log: false\r\n  # 是否从 cookie 中读取 token\r\n  is-read-cookie: false\r\n  # 是否从 head 中读取 token\r\n  is-read-header: true\r\n  # 是否从请求体（URL参数）里读取 token\r\n  is-read-body: true\r\n  # jwt秘钥（重要：请修改为你自己的秘钥，确保足够复杂）\r\n  jwt-secret-key: \"dd05f1c54d63749eda95f9fa6d49v442a\"\r\n  \r\nspring:\r\n  datasource:\r\n    druid:\r\n      stat-view-servlet:\r\n        enabled: true\r\n        loginUsername: admin\r\n        loginPassword: 123456\r\n        allow:\r\n      web-stat-filter:\r\n        enabled: true\r\n    dynamic:\r\n      druid:\r\n        initial-size: 5\r\n        min-idle: 5\r\n        maxActive: 20\r\n        maxWait: 60000\r\n        timeBetweenEvictionRunsMillis: 60000\r\n        minEvictableIdleTimeMillis: 300000\r\n        validationQuery: SELECT 1 FROM DUAL\r\n        testWhileIdle: true\r\n        testOnBorrow: false\r\n        testOnReturn: false\r\n        poolPreparedStatements: true\r\n        maxPoolPreparedStatementPerConnectionSize: 20\r\n        filters: stat,slf4j\r\n        wall:\r\n          selectWhereAlwayTrueCheck: false\r\n        stat:\r\n          merge-sql: true\r\n          slow-sql-millis: 5000\r\n      datasource:\r\n        master:\r\n          url: jdbc:mysql://jeecg-boot-mysql:3306/jeecg-boot?characterEncoding=UTF-8&useUnicode=true&useSSL=false&tinyInt1isBit=false&allowPublicKeyRetrieval=true&serverTimezone=Asia/Shanghai\r\n          username: root\r\n          password: root\r\n          driver-class-name: com.mysql.cj.jdbc.Driver\r\n        # sharding-db:\r\n        #  driver-class-name: org.apache.shardingsphere.driver.ShardingSphereDriver\r\n        #  url: jdbc:shardingsphere:nacos:sharding.yaml?serverAddr=${spring.cloud.nacos.config.server-addr}&namespace=${spring.cloud.nacos.config.namespace}&group=${spring.cloud.nacos.config.group}\r\n  data:\r\n    redis:\r\n      database: 0\r\n      host: jeecg-boot-redis\r\n      password:\r\n      port: 6379\r\n  rabbitmq:\r\n    host: jeecg-boot-rabbitmq\r\n    username: guest\r\n    password: guest\r\n    port: 5672\r\n    publisher-confirms: true\r\n    publisher-returns: true\r\n    virtual-host: /\r\n    listener:\r\n      simple:\r\n        acknowledge-mode: manual\r\n        concurrency: 1\r\n        max-concurrency: 1\r\n        retry:\r\n          enabled: true\r\n  flyway:\r\n    enabled: false\r\n    locations: classpath:flyway/sql/mysql\r\n    clean-disabled: true\r\nminidao:\r\n  base-package: org.jeecg.modules.jmreport.*,org.jeecg.modules.drag.*\r\njeecg:\r\n  firewall:\r\n    dataSourceSafe: false\r\n    lowCodeMode: dev\r\n  signatureSecret: dd05f1c54d63749eda95f9fa6d49v442a\r\n  signUrls: /sys/dict/getDictItems/*,/sys/dict/loadDict/*,/sys/dict/loadDictOrderByValue/*,/sys/dict/loadDictItem/*,/sys/dict/loadTreeData,/sys/api/queryTableDictItemsByCode,/sys/api/queryFilterTableDictInfo,/sys/api/queryTableDictByKeys,/sys/api/translateDictFromTable,/sys/api/translateDictFromTableByKeys\r\n  uploadType: local\r\n  domainUrl:\r\n    pc: http://localhost:3100\r\n    app: http://localhost:8051\r\n  path:\r\n    upload: /opt/upFiles\r\n    webapp: /opt/webapp\r\n  shiro:\r\n    excludeUrls: /test/jeecgDemo/demo3,/test/jeecgDemo/redisDemo/**,/category/**,/visual/**,/map/**,/jmreport/bigscreen2/**\r\n  oss:\r\n    endpoint: oss-cn-beijing.aliyuncs.com\r\n    accessKey: ??\r\n    secretKey: ??\r\n    bucketName: jeecgdev\r\n    staticDomain: ??  \r\n  file-view-domain: 127.0.0.1:8012\r\n  minio:\r\n    minio_url: http://minio.jeecg.com\r\n    minio_name: ??\r\n    minio_pass: ??\r\n    bucketName: otatest\r\n  jmreport:\r\n    saasMode:\r\n    firewall:\r\n      dataSourceSafe: false\r\n      lowCodeMode: dev\r\n  wps:\r\n    domain: https://wwo.wps.cn/office/\r\n    appid: ??\r\n    appsecret: ??\r\n  xxljob:\r\n    enabled: false\r\n    adminAddresses: http://jeecg-boot-xxljob:9080/xxl-job-admin\r\n    appname: ${spring.application.name}\r\n    accessToken: \'\'\r\n    logPath: logs/jeecg/job/jobhandler/\r\n    logRetentionDays: 30\r\n  redisson:\r\n    address: jeecg-boot-redis:6379\r\n    password:\r\n    type: STANDALONE\r\n    enabled: true\r\n  ai-chat:\r\n    enabled: false\r\n    apiKey: \"？？？？\"\r\n    apiHost: \"https://api.openai.com\"\r\n    timeout: 60\r\n  ai-rag:\r\n    embed-store:\r\n      host: 127.0.0.1\r\n      port: 5432\r\n      database: postgres\r\n      user: postgres\r\n      password: postgres\r\n      table: embeddings\r\ncas:\r\n  prefixUrl: http://localhost:8888/cas\r\nknife4j:\r\n  production: false\r\n  basic:\r\n    enable: false\r\n    username: jeecg\r\n    password: jeecg1314\r\njustauth:\r\n  enabled: true\r\n  type:\r\n    GITHUB:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/github/callback\r\n    WECHAT_ENTERPRISE:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/wechat_enterprise/callback\r\n      agent-id: ??\r\n    DINGTALK:\r\n      client-id: ??\r\n      client-secret: ??\r\n      redirect-uri: http://sso.test.com:8080/jeecg-boot/thirdLogin/dingtalk/callback\r\n  cache:\r\n    type: default\r\n    prefix: \'demo::\'\r\n    timeout: 1h\r\nthird-app:\r\n  enabled: false\r\n  type:\r\n    WECHAT_ENTERPRISE:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??\r\n    DINGTALK:\r\n      enabled: false\r\n      client-id: ??\r\n      client-secret: ??\r\n      agent-id: ??', '1c1b20938e6641f1c9a5c0ea94a0c1bd', '2026-07-06 22:48:39', '2026-07-06 22:48:40', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 4, 'jeecg-gateway.yaml', 'DEFAULT_GROUP', '', 'jeecg:\r\n  route:\r\n    config:\r\n      #type:database nacos yml\r\n      data-type: database\r\n      data-id: jeecg-gateway-router\r\nspring:\r\n  data:\r\n    redis:\r\n      database: 0\r\n      host: jeecg-boot-redis\r\n      port: 6379\r\n      password:\r\nknife4j:\r\n  production: false', 'e70570696e25cdaac7313be77cc64fe7', '2026-07-06 22:48:58', '2026-07-06 22:48:58', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (0, 5, 'jeecg-gateway-router.json', 'DEFAULT_GROUP', '', '[{\r\n  \"id\": \"jeecg-system\",\r\n  \"order\": 0,\r\n  \"predicates\": [{\r\n    \"name\": \"Path\",\r\n    \"args\": {\r\n      \"_genkey_0\": \"/sys/**\",\r\n      \"_genkey_1\": \"/jmreport/**\",\r\n      \"_genkey_3\": \"/online/**\",\r\n      \"_genkey_4\": \"/generic/**\",\r\n      \"_genkey_5\": \"/oauth2/**\",\r\n      \"_genkey_6\": \"/drag/**\",\r\n      \"_genkey_7\": \"/actuator/**\"\r\n    }\r\n  }],\r\n  \"filters\": [],\r\n  \"uri\": \"lb://jeecg-system\"\r\n}, {\r\n  \"id\": \"jeecg-demo\",\r\n  \"order\": 1,\r\n  \"predicates\": [{\r\n    \"name\": \"Path\",\r\n    \"args\": {\r\n      \"_genkey_0\": \"/mock/**\",\r\n      \"_genkey_1\": \"/test/**\",\r\n      \"_genkey_2\": \"/bigscreen/template1/**\",\r\n      \"_genkey_3\": \"/bigscreen/template2/**\"\r\n    }\r\n  }],\r\n  \"filters\": [],\r\n  \"uri\": \"lb://jeecg-demo\"\r\n}, {\r\n  \"id\": \"jeecg-system-websocket\",\r\n  \"order\": 2,\r\n  \"predicates\": [{\r\n    \"name\": \"Path\",\r\n    \"args\": {\r\n      \"_genkey_0\": \"/websocket/**\",\r\n      \"_genkey_1\": \"/newsWebsocket/**\"\r\n    }\r\n  }],\r\n  \"filters\": [],\r\n  \"uri\": \"lb:ws://jeecg-system\"\r\n}, {\r\n  \"id\": \"jeecg-demo-websocket\",\r\n  \"order\": 3,\r\n  \"predicates\": [{\r\n    \"name\": \"Path\",\r\n    \"args\": {\r\n      \"_genkey_0\": \"/vxeSocket/**\"\r\n    }\r\n  }],\r\n  \"filters\": [],\r\n  \"uri\": \"lb:ws://jeecg-demo\"\r\n}]', '4b447abdde61f2af2836bda0390b698c', '2026-07-06 22:49:17', '2026-07-06 22:49:17', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"json\"}');
INSERT INTO `his_config_info` VALUES (0, 6, 'sharding.yaml', 'DEFAULT_GROUP', '', 'databaseName: sharding-db\r\n\r\ndataSources:\r\n  db_0:\r\n    dataSourceClassName: com.zaxxer.hikari.HikariDataSource\r\n    driverClassName: com.mysql.cj.jdbc.Driver\r\n    jdbcUrl: jdbc:mysql://jeecg-boot-mysql:3306/jeecg-boot?useSSL=false&useUnicode=true&characterEncoding=utf-8&serverTimezone=Asia/Shanghai\r\n    password: root\r\n    username: root\r\n\r\nrules:\r\n  - !SHARDING\r\n    tables:\r\n      sys_log:\r\n        actualDataNodes: db_0.sys_log$->{0..1}\r\n        databaseStrategy:\r\n          none:\r\n        tableStrategy:\r\n          standard:\r\n            shardingColumn: log_type\r\n            shardingAlgorithmName: user_inline\r\n        keyGenerateStrategy:\r\n          column: id\r\n          keyGeneratorName: snowflake\r\n    keyGenerators:\r\n      snowflake:\r\n        type: SNOWFLAKE\r\n        props:\r\n          worker-id: 123\r\n    shardingAlgorithms:\r\n      user_inline:\r\n        type: INLINE\r\n        props:\r\n          algorithm-expression: sys_log$->{log_type % 2}\r\n\r\nprops:\r\n  sql-show: true', '349eeac4b34afbce196a57b017990172', '2026-07-06 22:49:36', '2026-07-06 22:49:36', 'nacos', '0:0:0:0:0:0:0:1', 'I', 'public', '', 'formal', '', '{\"src_user\":\"nacos\",\"type\":\"yaml\"}');
INSERT INTO `his_config_info` VALUES (2, 7, 'jeecg.yaml', 'DEFAULT_GROUP', '', 'server:\r\n  tomcat:\r\n    max-swallow-size: -1\r\n  error:\r\n    include-exception: true\r\n    include-stacktrace: ALWAYS\r\n    include-message: ALWAYS\r\n  compression:\r\n    enabled: true\r\n    min-response-size: 1024\r\n    mime-types: application/javascript,application/json,application/xml,text/html,text/xml,text/plain,text/css,image/*\r\nmanagement:\r\n  health:\r\n    mail:\r\n      enabled: false\r\n  endpoints:\r\n    web:\r\n      exposure:\r\n        include: metrics,httpexchanges,jeecghttptrace\r\n    health:\r\n      sensitive: true\r\n  endpoint:\r\n    health:\r\n      show-details: ALWAYS\r\nspring:\r\n  servlet:\r\n    multipart:\r\n      max-file-size: 10MB\r\n      max-request-size: 10MB\r\n  mail:\r\n    host: smtp.163.com\r\n    username: jeecgos@163.com\r\n    password: ??\r\n    properties:\r\n      mail.smtp.timeout: 10000\r\n      mail.smtp.connectiontimeout: 10000\r\n      mail.smtp.writetimeout: 10000\r\n      mail.smtp.auth: true\r\n      smtp.ssl.enable: true\r\n  quartz:\r\n    job-store-type: jdbc\r\n    jdbc:\r\n      initialize-schema: embedded\r\n    auto-startup: false\r\n    startup-delay: 1s\r\n    overwrite-existing-jobs: true\r\n    properties:\r\n      org:\r\n        quartz:\r\n          scheduler:\r\n            instanceName: MyScheduler\r\n            instanceId: AUTO\r\n          jobStore:\r\n            class: org.springframework.scheduling.quartz.LocalDataSourceJobStore\r\n            driverDelegateClass: org.quartz.impl.jdbcjobstore.StdJDBCDelegate\r\n            tablePrefix: QRTZ_\r\n            isClustered: true\r\n            misfireThreshold: 12000\r\n            clusterCheckinInterval: 15000\r\n          threadPool:\r\n            class: org.quartz.simpl.SimpleThreadPool\r\n            threadCount: 10\r\n            threadPriority: 5\r\n            threadsInheritContextClassLoaderOfInitializingThread: true\r\n  jackson:\r\n    date-format: yyyy-MM-dd HH:mm:ss\r\n    time-zone: GMT+8\r\n  aop:\r\n    proxy-target-class: true\r\n  jpa:\r\n    open-in-view: false\r\n  freemarker:\r\n    suffix: .ftl\r\n    content-type: text/html\r\n    charset: UTF-8\r\n    cache: false\r\n    prefer-file-system-access: false\r\n    template-loader-path:\r\n      - classpath:/templates\r\n  mvc:\r\n    static-path-pattern: /**\r\n    pathmatch:\r\n      matching-strategy: ant_path_matcher\r\n  resource:\r\n    static-locations: classpath:/static/,classpath:/public/\r\n  autoconfigure:\r\n    exclude:\r\n      - com.alibaba.druid.spring.boot3.autoconfigure.DruidDataSourceAutoConfigure\r\n      - org.springframework.boot.autoconfigure.flyway.FlywayAutoConfiguration\r\nmybatis-plus:\r\n  mapper-locations: classpath*:org/jeecg/**/xml/*Mapper.xml\r\n  global-config:\r\n    banner: false\r\n    db-config:\r\n      id-type: ASSIGN_ID\r\n      table-underline: true\r\n  configuration:\r\n    call-setters-on-nulls: true\r\nlogging:\r\n  level:\r\n    org.springframework.context.support.PostProcessorRegistrationDelegate: error\r\n    org.flywaydb: debug\r\n    org.jeecg.modules.system.mapper: info\r\n    org.jeecg.modules.demo.test.mapper: info\r\nliteflow:\r\n  print-banner: false\r\n  parse-mode: PARSE_ONE_ON_FIRST_EXEC\r\n  rule-source-ext-data-map:\r\n    applicationName: jeecg\r\n    #是否开启SQL日志\r\n    sqlLogEnabled: true\r\n    chainTableName: airag_flow\r\n    #编排规则表中应用名称存储字段名\r\n    chainApplicationNameField: application_name\r\n    #规则名称存储的字段名\r\n    chainNameField: id\r\n    #EL表达式的字段(只存EL)\r\n    elDataField: chain\r\n    chainCustomSql: select id, application_name, chain from airag_flow where status = \'enable\' and chain is not null', '7da782052bc66c0ee604183e75ef477c', '2026-07-06 22:55:00', '2026-07-06 22:55:00', 'nacos', '0:0:0:0:0:0:0:1', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (2, 8, 'jeecg.yaml', 'DEFAULT_GROUP', '', 'server:\n  tomcat:\n    max-swallow-size: -1\n  error:\n    include-exception: true\n    include-stacktrace: ALWAYS\n    include-message: ALWAYS\n  compression:\n    enabled: true\n    min-response-size: 1024\n    mime-types: application/javascript,application/json,application/xml,text/html,text/xml,text/plain,text/css,image/*\nmanagement:\n  health:\n    mail:\n      enabled: false\n  endpoints:\n    web:\n      exposure:\n        include: metrics,httpexchanges,jeecghttptrace\n    health:\n      sensitive: true\n  endpoint:\n    health:\n      show-details: ALWAYS\nspring:\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 10MB\n  mail:\n    host: smtp.163.com\n    username: jeecgos@163.com\n    password: ??\n    properties:\n      mail.smtp.timeout: 10000\n      mail.smtp.connectiontimeout: 10000\n      mail.smtp.writetimeout: 10000\n      mail.smtp.auth: true\n      smtp.ssl.enable: true\n  quartz:\n    job-store-type: jdbc\n    jdbc:\n      initialize-schema: embedded\n    auto-startup: false\n    startup-delay: 1s\n    overwrite-existing-jobs: true\n    properties:\n      org:\n        quartz:\n          scheduler:\n            instanceName: MyScheduler\n            instanceId: AUTO\n          jobStore:\n            class: org.springframework.scheduling.quartz.LocalDataSourceJobStore\n            driverDelegateClass: org.quartz.impl.jdbcjobstore.StdJDBCDelegate\n            tablePrefix: QRTZ_\n            isClustered: true\n            misfireThreshold: 12000\n            clusterCheckinInterval: 15000\n          threadPool:\n            class: org.quartz.simpl.SimpleThreadPool\n            threadCount: 10\n            threadPriority: 5\n            threadsInheritContextClassLoaderOfInitializingThread: true\n  jackson:\n    date-format: yyyy-MM-dd HH:mm:ss\n    time-zone: GMT+8\n  aop:\n    proxy-target-class: true\n  jpa:\n    open-in-view: false\n  freemarker:\n    suffix: .ftl\n    content-type: text/html\n    charset: UTF-8\n    cache: false\n    prefer-file-system-access: false\n    template-loader-path:\n      - classpath:/templates\n  mvc:\n    static-path-pattern: /**\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  resource:\n    static-locations: classpath:/static/,classpath:/public/\n  autoconfigure:\n    exclude:\n      - com.alibaba.druid.spring.boot3.autoconfigure.DruidDataSourceAutoConfigure\n      - org.springframework.boot.autoconfigure.flyway.FlywayAutoConfiguration\n      - org.springframework.boot.data.redis.autoconfigure.DataRedisAnnotationDrivenConfiguration\nmybatis-plus:\n  mapper-locations: classpath*:org/jeecg/**/xml/*Mapper.xml\n  global-config:\n    banner: false\n    db-config:\n      id-type: ASSIGN_ID\n      table-underline: true\n  configuration:\n    call-setters-on-nulls: true\nlogging:\n  level:\n    org.springframework.context.support.PostProcessorRegistrationDelegate: error\n    org.flywaydb: debug\n    org.jeecg.modules.system.mapper: info\n    org.jeecg.modules.demo.test.mapper: info\nliteflow:\n  print-banner: false\n  parse-mode: PARSE_ONE_ON_FIRST_EXEC\n  rule-source-ext-data-map:\n    applicationName: jeecg\n    #是否开启SQL日志\n    sqlLogEnabled: true\n    chainTableName: airag_flow\n    #编排规则表中应用名称存储字段名\n    chainApplicationNameField: application_name\n    #规则名称存储的字段名\n    chainNameField: id\n    #EL表达式的字段(只存EL)\n    elDataField: chain\n    chainCustomSql: select id, application_name, chain from airag_flow where status = \'enable\' and chain is not null', 'e07de7f7959229221cd9c08794141795', '2026-07-06 22:55:58', '2026-07-06 22:55:59', 'nacos', '0:0:0:0:0:0:0:1', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');

-- ----------------------------
-- Table structure for permissions
-- ----------------------------
DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions`  (
  `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
  `resource` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'resource',
  `action` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'action',
  UNIQUE INDEX `uk_role_permission`(`role`, `resource`, `action`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of permissions
-- ----------------------------

-- ----------------------------
-- Table structure for pipeline_execution
-- ----------------------------
DROP TABLE IF EXISTS `pipeline_execution`;
CREATE TABLE `pipeline_execution`  (
  `execution_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '执行ID',
  `resource_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源类型',
  `resource_name` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源名称',
  `namespace_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '命名空间ID',
  `version` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '版本',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '执行状态',
  `pipeline` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'pipeline节点结果JSON',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '修改时间',
  PRIMARY KEY (`execution_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI资源发布审核Pipeline执行记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of pipeline_execution
-- ----------------------------

-- ----------------------------
-- Table structure for roles
-- ----------------------------
DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles`  (
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'username',
  `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
  UNIQUE INDEX `idx_user_role`(`username`, `role`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

